class Membership_User_File_Uploads {
	private $option_key = 'mufu_user_files';

	public function __construct() {
		add_shortcode('user_file_upload_form', array($this, 'render_shortcode'));
		add_action('init', array($this, 'handle_upload'));
		add_action('show_user_profile', array($this, 'render_profile_section'));
		add_action('edit_user_profile', array($this, 'render_profile_section'));
		add_action('personal_options_update', array($this, 'handle_profile_upload'));
		add_action('edit_user_profile_update', array($this, 'handle_profile_upload'));
	}

	private function get_upload_dir() {
		$upload = wp_upload_dir();
		$base_dir = trailingslashit($upload['basedir']) . 'user-files/';
		$base_url = trailingslashit($upload['baseurl']) . 'user-files/';

		if (!file_exists($base_dir)) {
			wp_mkdir_p($base_dir);
		}

		$index_file = $base_dir . 'index.php';
		if (!file_exists($index_file)) {
			@file_put_contents($index_file, "<?php\n");
		}

		return array(
			'dir' => $base_dir,
			'url' => $base_url,
		);
	}

	private function get_allowed_mimes() {
		return array(
			'jpg|jpeg|jpe' => 'image/jpeg',
			'gif' => 'image/gif',
			'png' => 'image/png',
			'webp' => 'image/webp',
			'pdf' => 'application/pdf',
			'doc' => 'application/msword',
			'docx' => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
			'xls' => 'application/vnd.ms-excel',
			'xlsx' => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
			'ppt' => 'application/vnd.ms-powerpoint',
			'pptx' => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
			'txt' => 'text/plain',
			'rtf' => 'application/rtf',
			'odt' => 'application/vnd.oasis.opendocument.text',
		);
	}

	private function get_user_files($user_id) {
		$files = get_user_meta($user_id, $this->option_key, true);
		return is_array($files) ? $files : array();
	}

	private function save_user_files($user_id, $files) {
		update_user_meta($user_id, $this->option_key, $files);
	}

	private function process_upload($user_id, $file_field = 'mufu_file') {
		if (empty($_FILES[$file_field]) || empty($_FILES[$file_field]['name'])) {
			return new WP_Error('no_file', 'No file uploaded.');
		}

		if (!function_exists('wp_check_filetype_and_ext')) {
			require_once ABSPATH . 'wp-admin/includes/file.php';
		}

		$file = $_FILES[$file_field];

		if (!empty($file['error'])) {
			return new WP_Error('upload_error', 'Upload error code: ' . intval($file['error']));
		}

		$allowed_mimes = $this->get_allowed_mimes();
		$check = wp_check_filetype_and_ext($file['tmp_name'], $file['name'], $allowed_mimes);

		if (empty($check['ext']) || empty($check['type'])) {
			return new WP_Error('invalid_type', 'This file type is not allowed.');
		}

		$dirs = $this->get_upload_dir();
		$user_dir = trailingslashit($dirs['dir']) . intval($user_id) . '/';
		$user_url = trailingslashit($dirs['url']) . intval($user_id) . '/';

		if (!file_exists($user_dir)) {
			wp_mkdir_p($user_dir);
		}

		$filename = sanitize_file_name(wp_unique_filename($user_dir, $file['name']));
		$destination = $user_dir . $filename;

		if (!is_uploaded_file($file['tmp_name'])) {
			return new WP_Error('invalid_upload', 'Possible file upload attack detected.');
		}

		if (!move_uploaded_file($file['tmp_name'], $destination)) {
			return new WP_Error('move_failed', 'Failed to move uploaded file.');
		}

		@chmod($destination, 0644);

		$file_info = array(
			'name' => $filename,
			'original_name' => sanitize_text_field(wp_unslash($file['name'])),
			'url' => $user_url . rawurlencode($filename),
			'path' => $destination,
			'type' => $check['type'],
			'uploaded_at' => current_time('mysql'),
		);

		$files = $this->get_user_files($user_id);
		$files[] = $file_info;
		$this->save_user_files($user_id, $files);

		return $file_info;
	}

	public function handle_upload() {
		if (!is_user_logged_in()) {
			return;
		}

		if (empty($_POST['mufu_action']) || $_POST['mufu_action'] !== 'upload_file') {
			return;
		}

		if (empty($_POST['mufu_nonce']) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['mufu_nonce'])), 'mufu_upload')) {
			return;
		}

		$user_id = get_current_user_id();
		$result = $this->process_upload($user_id, 'mufu_file');

		$redirect = wp_get_referer() ? wp_get_referer() : home_url('/');

		if (is_wp_error($result)) {
			$redirect = add_query_arg('mufu_error', rawurlencode($result->get_error_message()), $redirect);
		} else {
			$redirect = add_query_arg('mufu_success', 1, $redirect);
		}

		wp_safe_redirect($redirect);
		exit;
	}

	public function render_shortcode() {
		if (!is_user_logged_in()) {
			return '<p>You must be logged in to upload files.</p>';
		}

		$user_id = get_current_user_id();
		$files = $this->get_user_files($user_id);

		ob_start();

		if (!empty($_GET['mufu_success'])) {
			echo '<div class="notice notice-success"><p>File uploaded successfully.</p></div>';
		}

		if (!empty($_GET['mufu_error'])) {
			echo '<div class="notice notice-error"><p>' . esc_html(wp_unslash($_GET['mufu_error'])) . '</p></div>';
		}

		?>
		<form method="post" enctype="multipart/form-data">
			<p>
				<label for="mufu_file">Upload Profile Picture or Document</label><br>
				<input type="file" name="mufu_file" id="mufu_file" required>
			</p>
			<p>
				<input type="hidden" name="mufu_action" value="upload_file">
				<input type="hidden" name="mufu_nonce" value="<?php echo esc_attr(wp_create_nonce('mufu_upload')); ?>">
				<button type="submit">Upload File</button>
			</p>
		</form>
		<?php

		if (!empty($files)) {
			echo '<h3>Your Uploaded Files</h3><ul>';
			foreach ($files as $file) {
				echo '<li><a href="' . esc_url($file['url']) . '" target="_blank" rel="noopener noreferrer">' . esc_html($file['original_name']) . '</a> (' . esc_html($file['type']) . ')</li>';
			}
			echo '</ul>';
		}

		return ob_get_clean();
	}

	public function render_profile_section($user) {
		if (!current_user_can('upload_files', $user->ID) && get_current_user_id() !== (int) $user->ID && !current_user_can('edit_user', $user->ID)) {
			return;
		}

		$files = $this->get_user_files($user->ID);
		?>
		<h2>User File Uploads</h2>
		<table class="form-table" role="presentation">
			<tr>
				<th><label for="mufu_profile_file">Upload File</label></th>
				<td>
					<input type="file" name="mufu_profile_file" id="mufu_profile_file">
					<p class="description">Allowed: images, PDF, DOC, DOCX, XLS, XLSX, PPT, PPTX, TXT, RTF, ODT.</p>
					<?php wp_nonce_field('mufu_profile_upload', 'mufu_profile_nonce'); ?>
				</td>
			</tr>
			<?php if (!empty($files)) : ?>
			<tr>
				<th>Existing Files</th>
				<td>
					<ul>
						<?php foreach ($files as $file) : ?>
							<li><a href="<?php echo esc_url($file['url']); ?>" target="_blank" rel="noopener noreferrer"><?php echo esc_html($file['original_name']); ?></a></li>
						<?php endforeach; ?>
					</ul>
				</td>
			</tr>
			<?php endif; ?>
		</table>
		<?php
	}

	public function handle_profile_upload($user_id) {
		if (!current_user_can('edit_user', $user_id) && get_current_user_id() !== (int) $user_id) {
			return;
		}

		if (empty($_POST['mufu_profile_nonce']) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['mufu_profile_nonce'])), 'mufu_profile_upload')) {
			return;
		}

		if (empty($_FILES['mufu_profile_file']) || empty($_FILES['mufu_profile_file']['name'])) {
			return;
		}

		$this->process_upload($user_id, 'mufu_profile_file');
	}
}

new Membership_User_File_Uploads();